import { type Tree } from '@nx/devkit';
import { join } from 'path';

export const defaultExclude = [
  'jest.config.[ct]s',
  '.*\\.spec.tsx?$',
  '.*\\.test.tsx?$',
  './src/jest-setup.ts$',
  './**/jest-setup.ts$',
  '.*.js$',
];

const swcOptionsString = (
  type: 'commonjs' | 'es6' = 'commonjs',
  exclude: string[],
  supportTsx: boolean
) => `{
  "jsc": {
    "target": "es2017",
    "parser": {
      "syntax": "typescript",
      "decorators": true,
      "dynamicImport": true${
        supportTsx
          ? `,
      "tsx": true`
          : ''
      }
    },
    "transform": {
      "decoratorMetadata": true,
      "legacyDecorator": true${
        supportTsx
          ? `,
      "react": {
        "runtime": "automatic"
      }`
          : ''
      }
    },
    "keepClassNames": true,
    "externalHelpers": true,
    "loose": true
  },
  "module": {
    "type": "${type}"
  },
  "sourceMaps": true,
  "exclude": ${JSON.stringify(exclude)}
}
`;

export function addSwcConfig(
  tree: Tree,
  projectDir: string,
  type: 'commonjs' | 'es6' = 'commonjs',
  supportTsx: boolean = false,
  swcName: string = '.swcrc',
  additionalExcludes: string[] = []
) {
  const swcrcPath = join(projectDir, swcName);
  if (tree.exists(swcrcPath)) return;
  tree.write(
    swcrcPath,
    swcOptionsString(
      type,
      [...defaultExclude, ...additionalExcludes],
      supportTsx
    )
  );
}

export function addSwcTestConfig(
  tree: Tree,
  projectDir: string,
  type: 'commonjs' | 'es6' = 'commonjs',
  supportTsx: boolean = false
) {
  const swcrcPath = join(projectDir, '.spec.swcrc');
  if (tree.exists(swcrcPath)) return;
  tree.write(swcrcPath, swcOptionsString(type, [], supportTsx));
}

import os from 'node:os'
import path from 'node:path'

import { GLOBAL_CONFIG_YAML_FILENAME } from '@pnpm/constants'

export function getGlobalConfigPath (configDir: string): string {
  return path.join(configDir, GLOBAL_CONFIG_YAML_FILENAME)
}

export function getCacheDir (
  opts: {
    env: NodeJS.ProcessEnv
    platform: string
  }
): string {
  if (opts.env.XDG_CACHE_HOME) {
    return path.join(opts.env.XDG_CACHE_HOME, 'pnpm')
  }
  if (opts.platform === 'darwin') {
    return path.join(os.homedir(), 'Library/Caches/pnpm')
  }
  if (opts.platform !== 'win32') {
    return path.join(os.homedir(), '.cache/pnpm')
  }
  if (opts.env.LOCALAPPDATA) {
    return path.join(opts.env.LOCALAPPDATA, 'pnpm-cache')
  }
  return path.join(os.homedir(), '.pnpm-cache')
}

export function getStateDir (
  opts: {
    env: NodeJS.ProcessEnv
    platform: string
  }
): string {
  if (opts.env.XDG_STATE_HOME) {
    return path.join(opts.env.XDG_STATE_HOME, 'pnpm')
  }
  if (opts.platform !== 'win32') {
    return path.join(os.homedir(), '.local/state/pnpm')
  }
  if (opts.env.LOCALAPPDATA) {
    return path.join(opts.env.LOCALAPPDATA, 'pnpm-state')
  }
  return path.join(os.homedir(), '.pnpm-state')
}

export function getDataDir (
  opts: {
    env: NodeJS.ProcessEnv
    platform: string
  }
): string {
  if (opts.env.PNPM_HOME) {
    return opts.env.PNPM_HOME
  }
  if (opts.env.XDG_DATA_HOME) {
    return path.join(opts.env.XDG_DATA_HOME, 'pnpm')
  }
  if (opts.platform === 'darwin') {
    return path.join(os.homedir(), 'Library/pnpm')
  }
  if (opts.platform !== 'win32') {
    return path.join(os.homedir(), '.local/share/pnpm')
  }
  if (opts.env.LOCALAPPDATA) {
    return path.join(opts.env.LOCALAPPDATA, 'pnpm')
  }
  return path.join(os.homedir(), '.pnpm')
}

export function getConfigDir (
  opts: {
    env: NodeJS.ProcessEnv
    platform: string
  }
): string {
  if (opts.env.XDG_CONFIG_HOME) {
    return path.join(opts.env.XDG_CONFIG_HOME, 'pnpm')
  }
  if (opts.platform === 'darwin') {
    return path.join(os.homedir(), 'Library/Preferences/pnpm')
  }
  if (opts.platform !== 'win32') {
    return path.join(os.homedir(), '.config/pnpm')
  }
  if (opts.env.LOCALAPPDATA) {
    return path.join(opts.env.LOCALAPPDATA, 'pnpm/config')
  }
  return path.join(os.homedir(), '.config/pnpm')
}

