function hexToAnsi256(sHex: string): number {
  const rgb = Number.parseInt(sHex.slice(1), 16);
  const r = Math.floor(rgb / (256 * 256)) % 256;
  const g = Math.floor(rgb / 256) % 256;
  const b = rgb % 256;

  const ansi =
    16 +
    36 * Math.round((r / 255) * 5) +
    6 * Math.round((g / 255) * 5) +
    Math.round((b / 255) * 5);
  return ansi;
}

import type { TestBenchmark, TestBenchmarkTask } from '../../../runtime/runner/types'
import { stripVTControlCharacters } from 'node:util'

export const BENCH_TABLE_HEAD: string[] = [
  'hz',
  'min',
  'max',
  'mean',
  'p75',
  'p99',
  'p995',
  'p999',
  'rme',
  'samples',
]

function formatBenchNumber(number: number): string {
  const res = String(number.toFixed(number < 100 ? 4 : 2)).split('.')
  return res[0].replace(/(?=(?:\d{3})+$)\B/g, ',') + (res[1] ? `.${res[1]}` : '')
}

// Plain-text rendering of the benchmark table (no ANSI colors, no indent).
// Used by the junit reporter to embed benchmark data in <system-out>.
export function renderBenchmarkTableText(
  benchmarks: readonly TestBenchmark[],
  columnName = 'name',
): string {
  const lines: string[] = []
  for (const benchmark of benchmarks) {
    const { tasks } = benchmark
    if (tasks.length === 0) {
      continue
    }
    if (lines.length > 0) {
      lines.push('')
    }
    const rows = tasks.map(renderBenchmarkRow)
    const head = [columnName, ...BENCH_TABLE_HEAD]
    const widths = computeBenchColumnWidths(head, rows)
    lines.push(padBenchRow(head, widths).join('  '))
    for (const task of tasks) {
      let row = padBenchRow(renderBenchmarkRow(task), widths).join('  ')
      if (task.rank === 1 && tasks.length > 1) {
        row += '   fastest'
      }
      if (task.rank === tasks.length && tasks.length > 2) {
        row += '   slowest'
      }
      lines.push(row)
    }
  }
  return lines.join('\n')
}

export function renderBenchmarkRow(task: TestBenchmarkTask): string[] {
  return [
    task.name,
    formatBenchNumber(task.throughput.mean || 0),
    formatBenchNumber(task.latency.min || 0),
    formatBenchNumber(task.latency.max || 0),
    formatBenchNumber(task.latency.mean || 0),
    formatBenchNumber(task.latency.p75 || 0),
    formatBenchNumber(task.latency.p99 || 0),
    formatBenchNumber(task.latency.p995 || 0),
    formatBenchNumber(task.latency.p999 || 0),
    `\u00B1${(task.latency.rme || 0).toFixed(2)}%`,
    String(task.latency.samplesCount || 0),
  ]
}

export function computeBenchColumnWidths(header: string[], rows: string[][]): number[] {
  const allRows = [header, ...rows]
  return Array.from(header, (_, i) => Math.max(...allRows.map(row => stripVTControlCharacters(row[i]).length)))
}

export function padBenchRow(row: string[], widths: number[]): string[] {
  return row.map(
    (v, i) => (i === 0 ? v.padEnd(widths[i]) : v.padStart(widths[i])),
  )
}

import { bench, describe } from 'vitest'
import type { Ref } from '../src'
import { effect, ref } from '../dist/reactivity.esm-browser.prod'

describe('effect', () => {
  {
    let i = 0
    const n = ref(0)
    effect(() => n.value)
    bench('single ref invoke', () => {
      n.value = i++
    })
  }

  function benchEffectCreate(size: number) {
    bench(`create an effect that tracks ${size} refs`, () => {
      const refs: Ref[] = []
      for (let i = 0; i < size; i++) {
        refs.push(ref(i))
      }
      effect(() => {
        for (let i = 0; i < size; i++) {
          refs[i].value
        }
      })
    })
  }

  benchEffectCreate(1)
  benchEffectCreate(10)
  benchEffectCreate(100)
  benchEffectCreate(1000)

  function benchEffectCreateAndStop(size: number) {
    bench(`create and stop an effect that tracks ${size} refs`, () => {
      const refs: Ref[] = []
      for (let i = 0; i < size; i++) {
        refs.push(ref(i))
      }
      const e = effect(() => {
        for (let i = 0; i < size; i++) {
          refs[i].value
        }
      })
      e.effect.stop()
    })
  }

  benchEffectCreateAndStop(1)
  benchEffectCreateAndStop(10)
  benchEffectCreateAndStop(100)
  benchEffectCreateAndStop(1000)

  function benchWithRefs(size: number) {
    let j = 0
    const refs: Ref[] = []
    for (let i = 0; i < size; i++) {
      refs.push(ref(i))
    }
    effect(() => {
      for (let i = 0; i < size; i++) {
        refs[i].value
      }
    })
    bench(`1 effect, mutate ${size} refs`, () => {
      for (let i = 0; i < size; i++) {
        refs[i].value = i + j++
      }
    })
  }

  benchWithRefs(10)
  benchWithRefs(100)
  benchWithRefs(1000)

  function benchWithBranches(size: number) {
    const toggle = ref(true)
    const refs: Ref[] = []
    for (let i = 0; i < size; i++) {
      refs.push(ref(i))
    }
    effect(() => {
      if (toggle.value) {
        for (let i = 0; i < size; i++) {
          refs[i].value
        }
      }
    })
    bench(`${size} refs branch toggle`, () => {
      toggle.value = !toggle.value
    })
  }

  benchWithBranches(10)
  benchWithBranches(100)
  benchWithBranches(1000)

  function benchMultipleEffects(size: number) {
    let i = 0
    const n = ref(0)
    for (let i = 0; i < size; i++) {
      effect(() => n.value)
    }
    bench(`1 ref invoking ${size} effects`, () => {
      n.value = i++
    })
  }

  benchMultipleEffects(10)
  benchMultipleEffects(100)
  benchMultipleEffects(1000)
})

import {VirtualFS, PosixFS, npath} from '@yarnpkg/fslib';
import {ZipOpenFS}                 from '@yarnpkg/libzip';
import * as vscode                 from 'vscode';

export class ZipFSProvider implements vscode.FileSystemProvider {
  private readonly fs = new PosixFS(
    new VirtualFS({
      baseFs: new ZipOpenFS({
        useCache: true,
        maxOpenFiles: 80,
      }),
    }),
  );

  stat(uri: vscode.Uri): vscode.FileStat {
    const stat: any = this.fs.statSync(uri.fsPath);

    switch (true) {
      case stat.isDirectory():
      case npath.extname(uri.fsPath) === `.zip`: {
        stat.type = vscode.FileType.Directory;
      } break;

      case stat.isFile(): {
        stat.type = vscode.FileType.File;
      } break;

      case stat.isSymbolicLink(): {
        stat.type = vscode.FileType.SymbolicLink;
      } break;

      default: {
        stat.type = vscode.FileType.Unknown;
      } break;
    }

    return stat;
  }

  readDirectory(uri: vscode.Uri): Array<[string, vscode.FileType]> {
    const listing = this.fs.readdirSync(uri.fsPath);

    return listing.map(entry => {
      const {type} = this.stat(vscode.Uri.joinPath(uri, entry));
      return [entry, type];
    });
  }

  readFile(uri: vscode.Uri): Uint8Array {
    return this.fs.readFileSync(uri.fsPath);
  }

  writeFile(uri: vscode.Uri, content: Uint8Array, options: {create: boolean, overwrite: boolean}): void {
    if (!options.create && !this.fs.existsSync(uri.fsPath))
      throw vscode.FileSystemError.FileNotFound(uri);
    if (options.create && !options.overwrite && this.fs.existsSync(uri.fsPath))
      throw vscode.FileSystemError.FileExists(uri);

    this.fs.writeFileSync(uri.fsPath, Buffer.from(content));
  }

  rename(oldUri: vscode.Uri, newUri: vscode.Uri, options: {overwrite: boolean}): void {
    throw new Error(`Not supported`);
  }

  delete(uri: vscode.Uri, options: {recursive: boolean}): void {
    this.fs.removeSync(uri.fsPath, options);
  }

  createDirectory(uri: vscode.Uri): void {
    this.fs.mkdirSync(uri.fsPath);
  }

  private _emitter = new vscode.EventEmitter<Array<vscode.FileChangeEvent>>();
  readonly onDidChangeFile = this._emitter.event;

  watch(resource: vscode.Uri, opts: any): vscode.Disposable {
    return new vscode.Disposable(() => {});
  }
}
